+        int a = 0;
+        for (int i = stop; i > 0; i--) {
+            a += inc;
+        }
+        return a;
+    }
+
+    @Run(test = "countDown")
+    private static void runCountDown() {
+        int s = G.ints().restricted(0, Integer.MAX_VALUE).next();
+        int inc = G.ints().next();
+        Asserts.assertEQ(s * inc, countDown(s, inc));
+    }
