+    private static long multipleIVs(int stop, int incA, long incB) {
+        int a = 0;
+        long b = 0;
+        for (int i = 0; i < stop; i++) {
+            a += incA;
+            b += incB;
+        }
+        return a + b;
+    }
+
+    @Run(test = "multipleIVs")
