+        int s = G.ints().restricted(0, Integer.MAX_VALUE).next();
+        int incA = G.ints().next();
+        long incB = G.longs().next();
+        long expected = (long)(s * incA) + ((long) s * incB);
+        Asserts.assertEQ(expected, multipleIVs(s, incA, incB));
+    }
